BEGIN;\nDELETE FROM report_analysts;\nDELETE FROM report_tags;\nDELETE FROM research_reports;\nDELETE FROM analysts;\nINSERT INTO analysts (id, name, title, bio, avatar_url, is_active) VALUES ('1', 'Tajudeen Ibrahim', 'Director, Research', 'Tajudeen Ibrahim leads the research function and coordinates coverage priorities across Chapel Hill Denham''s institutional research platform. His work focuses on telecommunications, market strategy and the interpretation of sector developments for investor decision-making.', 'public_assets/analysts/tajudeen-ibrahim.jpg', true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;\nINSERT INTO analysts (id, name, title, bio, avatar_url, is_active) VALUES ('2', 'Nabila Mohammed', 'Analyst', 'Nabila Mohammed covers financial services, with emphasis on bank earnings, balance-sheet trends, capital adequacy and sector regulation. Her research supports institutional clients with concise analysis of valuation drivers and operating performance.', 'public_assets/analysts/nabila-mohammed.jpg', true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;\nINSERT INTO analysts (id, name, title, bio, avatar_url, is_active) VALUES ('3', 'Gideon Oshadumi', 'Analyst', 'Gideon Oshadumi covers cement and selected financial-services names, focusing on earnings quality, pricing trends, cost pressures and balance-sheet resilience. His work combines company analysis with sector context for actionable research views.', 'public_assets/analysts/gideon-oshadumi.jpg', true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;\nINSERT INTO analysts (id, name, title, bio, avatar_url, is_active) VALUES ('4', 'Boluwatife Ishola', 'Analyst', 'Boluwatife Ishola covers FMCG and agriculture-linked equities, tracking consumer demand, pricing power, input costs and margin trends. Her research focuses on the operating factors shaping listed companies in Nigeria''s consumer economy.', 'public_assets/analysts/boluwatife-ishola.jpg', true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;\nINSERT INTO analysts (id, name, title, bio, avatar_url, is_active) VALUES ('5', 'Bolade Agboola', 'Analyst', 'Bolade Agboola supports coverage across oil & gas and FMCG, with a focus on market developments, company fundamentals and sector themes. Her work contributes to timely research notes and the broader Chapel Hill Denham house view.', 'public_assets/analysts/bolade-agboola.jpg', true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;\nINSERT INTO analysts (id, name, title, bio, avatar_url, is_active) VALUES ('6', 'Chapel Hill Denham Research', 'Department Research / Routine Research', 'The House View represents Chapel Hill Denham Research''s consolidated perspective across equity, macroeconomic, sector and market strategy coverage. It is used where a report reflects the desk''s institutional view rather than a single named analyst.', '', true) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name;\nINSERT INTO research_reports (id, title, summary, published_at, document_url, publish_status, visibility, source_system, legacy_id) VALUES ('codex_2025-debt-tai_2025-09-11', '2025 Debt TAI', 'Legacy fixed income document staged for manual review: 2025 Debt TAI.', '2025-09-11', 'reports/staged/2025-debt-tai-updated.pdf', 'needs_review', 'internal', 'codex_manifest', NULL) ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title;\nINSERT INTO research_reports (id, title, summary, published_at, document_url, publish_status, visibility, source_system, legacy_id) VALUES ('codex_accesscorp-company-update-2025_2025-11-14', 'Accesscorp Company Update 2025', 'Legacy research report document staged for manual review: Accesscorp Company Update 2025.', '2025-11-14', 'reports/staged/accesscorp-company-update-2025-updated-final.pdf', 'needs_review', 'internal', 'codex_manifest', NULL) ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title;\nINSERT INTO research_reports (id, title, summary, published_at, document_url, publish_status, visibility, source_system, legacy_id) VALUES (